@Service
public class OwnerService {
    private final OwnerRepository ownerRepo;
    public OwnerService(OwnerRepository ownerRepo) { this.ownerRepo = ownerRepo; }

    public Owner findByName(String name) {
        return ownerRepo.findByLastName(name).stream().findFirst().orElse(null);
    }
}

@RestController
public class PetController {
    private final PetRepository petRepo;
    private final OwnerRepository ownerRepo;
    public PetController(PetRepository petRepo, OwnerRepository ownerRepo) {
        this.petRepo = petRepo;
        this.ownerRepo = ownerRepo;
    }

    @PostMapping("/owners/{ownerId}/pets")
    public ResponseEntity<Pet> addPet(@PathVariable Long ownerId, @RequestBody Pet pet) {
        Owner owner = ownerRepo.findById(ownerId).orElseThrow();
        pet.setOwner(owner);
        pet.setRegistrationDate(LocalDate.now());
        if (pet.getName() == null || pet.getName().isBlank()) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "name required");
        }
        petRepo.save(pet);
        return ResponseEntity.ok(pet);
    }
}

@Service
public class DataService {
    private final OwnerRepository repo;
    public DataService(OwnerRepository repo) { this.repo = repo; }

    public List<Owner> get(String s, int t) {
        var l = repo.findAll();
        return l.stream().filter(o -> o.getName().contains(s)).limit(t).toList();
    }
}

