export class PetService {
    constructor(private http: HttpClient) {}

    getById(id: number): Observable<any> {
        return this.http.get<any>(`/api/pets/${id}`);
    }

    update(pet: any): Observable<any> {
        return this.http.put<any>(`/api/pets/${pet.id}`, pet);
    }
}

