export class OwnerSearchComponent {
    owners: Owner[] = [];
    searchTerm = '';

    constructor(private http: HttpClient) {}

    search() {
        this.http.get<Owner[]>('/api/owners').subscribe(all => {
            this.owners = all.filter(o =>
                o.lastName.toLowerCase().includes(this.searchTerm.toLowerCase())
            );
        });
    }
}

