export class OwnerAddComponent {
    owner: any = {};
    errors: string[] = [];

    constructor(private http: HttpClient, private router: Router) {}

    save() {
        this.errors = [];
        if (!this.owner.firstName) this.errors.push('First name required');
        if (!this.owner.lastName) this.errors.push('Last name required');
        if (this.errors.length > 0) return;

        this.http.post<any>('/api/owners', this.owner).subscribe(
            () => this.router.navigate(['/owners']),
            err => this.errors.push(err.message)
        );
    }
}

